yId, Namespace, QualifiedCollectionId};\\n6\\tuse axon_core::types::{Entity, Link};\\n7\\tuse axon_schema::schema::{CollectionSchema, CollectionView};\\n8\\t\\n9\\t/// A typed index value extracted from entity data.\\n10\\t///\\n11\\t/// Values are stored in EAV index tables, one variant per [`IndexType`].\\n12\\t/// The `Ord` implementation provides the sort order used for range scans.\\n13\\t#[derive(Debug, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]\\n14\\tpub enum IndexValue {\\n15\\t    /// UTF-8 string value.\\n16\\t    String(String),\\n17\\t    /// Signed 64-bit integer.\\n18\\t    Integer(i64),\\n19\\t    /// IEEE 754 float, stored as ordered bits for BTreeMap compatibility.\\n20\\t    Float(OrderedFloat),\\n21\\t    /// Boolean value (false \u003c true).\\n22\\t    Boolean(bool),\\n23\\t}\\n24\\t\\n25\\timpl std::fmt::Display for IndexValue {\\n26\\t    fn fmt(\u0026self, f: \u0026mut std::fmt::Formatter\u003c'_\u003e) -\u003e std::fmt::Result {\\n27\\t        match self {\\n28\\t            IndexValue::String(s) =\u003e write!(f, \\\"\\\\\\\"{s}\\\\\\\"\\\"),\\n29\\t            IndexValue::Integer(n) =\u003e write!(f, \\\"{n}\\\"),\\n30\\t            IndexValue::Float(OrderedFloat(bits)) =\u003e {\\n31\\t                write!(f, \\\"{}\\\", f64::from_bits(*bits))\\n32\\t            }\\n33\\t            IndexValue::Boolean(b) =\u003e write!(f, \\\"{b}\\\"),\\n34\\t        }\\n35\\t    }\\n36\\t}\\n37\\t\\n38\\t/// Wrapper for f64 that implements `Eq` and `Ord` via total ordering on bits.\\n39\\t///\\n40\\t/// NaN values are sorted after all other values. This enables use as a\\n41\\t/// BTreeMap key.\\n42\\t#[derive(Debug, Clone, Copy)]\\n43\\tpub struct OrderedFloat(pub u64);\\n44\\t\\n45\\timpl OrderedFloat {\\n46\\t    pub fn new(val: f64) -\u003e Self {\\n47\\t        Self(val.to_bits())\\n48\\t    }\\n49\\t\\n50\\t    pub fn value(\u0026self) -\u003e f64 {\\n51\\t        f64::from_bits(self.0)\\n52\\t    }\\n53\\t}\\n54\\t\\n55\\timpl PartialEq for OrderedFloat {\\n56\\t    fn eq(\u0026self, other: \u0026Self) -\u003e bool {\\n57\\t        self.0 == other.0\\n58\\t    }\\n59\\t}\\n60\\timpl Eq for OrderedFloat {}\\n61\\t\\n62\\timpl std::hash::Hash for OrderedFloat {\\n63\\t    fn hash\u003cH: std::hash::Hasher\u003e(\u0026self, state: \u0026mut H) {\\n64\\t        self.0.hash(state);\\n65\\t    }\\n66\\t}\\n67\\t\\n68\\timpl PartialOrd for OrderedFloat {\\n69\\t    fn partial_cmp(\u0026self, other: \u0026Self) -\u003e Option\u003cstd::cmp::Ordering\u003e {\\n70\\t        Some(self.cmp(other))\\n71\\t    }\\n72\\t}\\n73\\t\\n74\\timpl Ord for OrderedFloat {\\n75\\t    fn cmp(\u0026self, other: \u0026Self) -\u003e std::cmp::Ordering {\\n76\\t        let a = f64::from_bits(self.0);\\n77\\t        let b = f64::from_bits(other.0);\\n78\\t        a.total_cmp(\u0026b)\\n79\\t    }\\n80\\t}\\n81\\t\\n82\\t/// Extract an [`IndexValue`] from a JSON value according to the declared index type.\\n83\\t///\\n84\\t/// Returns `None` if the value is null, missing, or has a type mismatch\\n85\\t/// (per FEAT-013: mismatched types are not indexed, not errors).\\n86\\tpub fn extract_index_value(\\n87\\t    json_val: \u0026serde_json::Value,\\n88\\t    index_type: \u0026axon_schema::schema::IndexType,\\n89\\t) -\u003e Option\u003cIndexValue\u003e {\\n90\\t    use axon_schema::schema::IndexType;\\n91\\t    match index_type {\\n92\\t        IndexType::String =\u003e json_val.as_str().map(|s| IndexValue::String(s.to_string())),\\n93\\t        IndexType::Integer =\u003e json_val.as_i64().map(IndexValue::Integer),\\n94\\t        IndexType::Float =\u003e json_val\\n95\\t            .as_f64()\\n96\\t            .map(|f| IndexValue::Float(OrderedFloat::new(f))),\\n97\\t        IndexType::Boolean =\u003e json_val.as_bool().map(IndexValue::Boolean),\\n98\\t        IndexType::Datetime =\u003e {\\n99\\t            // Datetimes are stored as strings for ordering purposes.\\n100\\t            json_val.as_str().map(|s| IndexValue::String(s.to_string()))\\n101\\t        }\\n102\\t    }\\n103\\t}\\n104\\t\\n105\\t/// A compound index key: ordered list of field values for multi-field indexes.\\n106\\t///\\n107\\t/// Implements `Ord` lexicographically, enabling prefix matching via\\n108\\t/// BTreeMap range scans.\\n109\\t#[derive(Debug, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]\\n110\\tpub struct CompoundKey(pub Vec\u003cIndexValue\u003e);\\n111\\t\\n112\\t/// Extract a compound key from entity data given a compound index definition.\\n113\\t///\\n114\\t/// Returns `None` if any field in the compound key is null/missing/type-mismatch,\\n115\\t/// since compound index entries require all fields to be present.\\n116\\tpub fn extract_compound_key(\\n117\\t    data: \u0026serde_json::Value,\\n118\\t    fields: \u0026[axon_schema::schema::CompoundIndexField],\\n119\\t) -\u003e Option\u003cCompoundKey\u003e {\\n120\\t    let mut values = Vec::with_capacity(fields.len());\\n121\\t    for f in fields {\\n122\\t        let json_val = resolve_field_path(data, \u0026f.field)?;\\n123\\t        let val = extract_index_value(json_val, \u0026f.index_type)?;\\n124\\t        values.push(val);\\n125\\t    }\\n126\\t    Some(CompoundKey(values))\\n127\\t}\\n128\\t\\n129\\t/// Navigate a dotted field path in a JSON value.\\n130\\t///\\n131\\t/// E.g., `\\\"address.city\\\"` resolves `{\\\"address\\\": {\\\"city\\\": \\\"NY\\\"}}` to `\\\"NY\\\"`.\\n132\\tpub fn resolve_field_path\u003c'a\u003e(\\n133\\t    data: \u0026'a serde_json::Value,\\n134\\t    path: \u0026str,\\n135\\t) -\u003e Option\u003c\u0026'a serde_json::Value\u003e {\\n136\\t    let mut current = data;\\n137\\t    for segment in path.split('.') {\\n138\\t        current = current.get(segment)?;\\n139\\t    }\\n140\\t    Some(current)\\n141\\t}\\n142\\t\\n143\\t/// Abstraction over Axon's backing storage.\\n144\\t///\\n145\\t/// Implementations wrap specific databases (SQLite, PostgreSQL, FoundationDB).\\n146\\t/// All operations are executed within the context of the adapter's internal\\n147\\t/// transaction semantics.\\n148\\tpub trait StorageAdapter: Send + Sync {\\n149\\t    /// Retrieves an entity by collection and ID.\\n150\\t    fn get(\u0026self, collection: \u0026CollectionId, id: \u0026EntityId) -\u003e Result\u003cOption\u003cEntity\u003e, AxonError\u003e;\\n151\\t\\n152\\t    /// Stores an entity, overwriting any existing entity with the same ID.\\n153\\t    /// Use this for initial inserts. For versioned updates, use [`compare_and_swap`].\\n154\\t    fn put(\u0026mut self, entity: Entity) -\u003e Result\u003c(), AxonError\u003e;\\n155\\t\\n156\\t    /// Deletes an entity. Returns `Ok(())` whether or not the entity existed.\\n157\\t    fn delete(\u0026mut self, collection: \u0026CollectionId, id: \u0026EntityId) -\u003e Result\u003c(), AxonError\u003e;\\n158\\t\\n159\\t    /// Returns the number of entities in the given collection.\\n160\\t    fn count(\u0026self, collection: \u0026CollectionId) -\u003e Result\u003cusize, AxonError\u003e;\\n161\\t\\n162\\t    /// Returns entities in a collection ordered by entity ID.\\n163\\t    ///\\n164\\t    /// - `start`: inclusive lower bound (no lower bound if `None`)\\n165\\t    /// - `end`: inclusive upper bound (no upper bound if `None`)\\n166\\t    /// - `limit`: maximum number of results (unlimited if `None`)\\n167\\t    fn range_scan(\\n168\\t        \u0026self,\\n169\\t        collection: \u0026CollectionId,\\n170\\t        start: Option\u003c\u0026EntityId\u003e,\\n171\\t        end: Option\u003c\u0026EntityId\u003e,\\n172\\t        limit: Option\u003cusize\u003e,\\n173\\t    ) -\u003e Result\u003cVec\u003cEntity\u003e, AxonError\u003e;\\n174\\t\\n175\\t    /// Atomically updates an entity using optimistic concurrency control (OCC).\\n176\\t    ///\\n177\\t    /// Writes `entity` only if the current stored version equals `expected_version`.\\n178\\t    /// On success, the stored version is incremented to `expected_version + 1` and\\n179\\t    /// the updated entity is returned.\\n180\\t    ///\\n181\\t    /// Returns [`AxonError::ConflictingVersion`] if the version does not match or\\n182\\t    /// the entity does not exist.\\n183\\t    fn compare_and_swap(\\n184\\t        \u0026mut self,\\n185\\t        entity: Entity,\\n186\\t        expected_version: u64,\\n187\\t    ) -\u003e Result\u003cEntity, AxonError\u003e;\\n188\\t\\n189\\t    /// Atomically inserts `entity` only if no live entity currently exists.\\n190\\t    ///\\n191\\t    /// This is used for rollback/recovery flows that recreate a deleted entity\\n192\\t    /// after the caller has already validated the deleted version via audit\\n193\\t    /// history. `expected_absent_version` is echoed back in\\n194\\t    /// [`AxonError::ConflictingVersion`] when another writer recreated the\\n195\\t    /// entity first.\\n196\\t    fn create_if_absent(\\n197\\t        \u0026mut self,\\n198\\t        entity: Entity,\\n199\\t        expected_absent_version: u64,\\n200\\t    ) -\u003e Result\u003cEntity, AxonError\u003e;\\n201\\t\\n202\\t    /// Begin a storage-level transaction.\\n203\\t    ///\\n204\\t    /// After this call, all writes are buffered or protected until [`commit_tx`]\\n205\\t    /// or [`abort_tx`] is called. Callers must call exactly one of those to\\n206\\t    /// end the transaction.\\n207\\t    ///\\n208\\t    /// The default implementation is a no-op (suitable for adapters whose\\n209\\t    /// mutation methods are already atomic or whose concurrency model does\\n210\\t    /// not require explicit transactions).\\n211\\t    fn begin_tx(\u0026mut self) -\u003e Result\u003c(), AxonError\u003e {\\n212\\t        Ok(())\\n213\\t    }\\n214\\t\\n215\\t    /// Commit the current transaction, making all buffered writes durable.\\n216\\t    ///\\n217\\t    /// Returns an error if no transaction is active.\\n218\\t    /// The default implementation is a no-op.\\n219\\t    fn commit_tx(\u0026mut self) -\u003e Result\u003c(), AxonError\u003e {\\n220\\t        Ok(())\\n221\\t    }\\n222\\t\\n223\\t    /// Abort the current transaction, discarding all buffered writes.\\n224\\t    ///\\n225\\t    /// Idempotent: calling `abort_tx` when no transaction is active is not an error.\\n226\\t    /// The default implementation is a no-op.\\n227\\t    fn abort_tx(\u0026mut self) -\u003e Result\u003c(), AxonError\u003e {\\n228\\t        Ok(())\\n229\\t    }\\n230\\t\\n231\\t    // ── Audit log (co-located writes) ────────────────────────────────────────\\n232\\t\\n233\\t    /// Append an audit entry within the current storage transaction.\\n234\\t    ///\\n235\\t    /// This is called **inside** `begin_tx` / `commit_tx` so that the audit\\n236\\t    /// write is part of the same atomic database transaction as entity\\n237\\t    /// mutations. If the storage transaction is later rolled back, the audit\\n238\\t    /// entry is rolled back too.\\n239\\t    ///\\n240\\t    /// The implementation must assign `entry.id` (from the backing store's\\n241\\t    /// sequence) and `entry.timestamp_ns` (current wall-clock time) if they\\n242\\t    /// are still at their zero sentinel values, then persist the entry.\\n243\\t    ///\\n244\\t    /// The default implementation is a no-op that returns the entry unchanged.\\n245\\t    /// Adapters that support co-located audit writes (e.g. SQLite) should\\n246\\t    /// override this method.\\n247\\t    fn append_audit_entry(\u0026mut self, entry: AuditEntry) -\u003e Result\u003cAuditEntry, AxonError\u003e {\\n248\\t        Ok(entry)\\n249\\t    }\\n250\\t\\n251\\t    // ── Database and namespace catalogs (FEAT-014) ─────────────────────────\\n252\\t\\n253\\t    /// Create a database and its default schema.\\n254\\t    fn create_database(\u0026mut self, _name: \u0026str) -\u003e Result\u003c(), AxonError\u003e {\\n255\\t        Ok(())\\n256\\t    }\\n257\\t\\n258\\t    /// Return all database names in ascending order.\\n259\\t    fn list_databases(\u0026self) -\u003e Result\u003cVec\u003cString\u003e, AxonError\u003e {\\n260\\t        Ok(vec![])\\n261\\t    }\\n262\\t\\n263\\t    /// Drop a database catalog entry after its collections have been removed.\\n264\\t    fn drop_database(\u0026mut self, _name: \u0026str) -\u003e Result\u003c(), AxonError\u003e {\\n265\\t        Ok(())\\n266\\t    }\\n267\\t\\n268\\t    /// Create a schema namespace within an existing database.\\n269\\t    fn create_namespace(\u0026mut self, _namespace: \u0026Namespace) -\u003e Result\u003c(), AxonError\u003e {\\n270\\t        Ok(())\\n271\\t    }\\n272\\t\\n273\\t    /// Return all schema names within a database in ascending order.\\n274\\t    fn list_namespaces(\u0026self, _database: \u0026str) -\u003e Result\u003cVec\u003cString\u003e, AxonError\u003e {\\n275\\t        Ok(vec![])\\n276\\t    }\\n277\\t\\n278\\t    /// Drop a schema namespace after its collections have been removed.\\n279\\t    fn drop_namespace(\u0026mut self, _namespace: \u0026Namespace) -\u003e Result\u003c(), AxonError\u003e {\\n280\\t        Ok(())\\n281\\t    }\\n282\\t\\n283\\t    /// Return collections registered within a namespace in ascending order.\\n284\\t    fn list_namespace_collections(\\n285\\t        \u0026self,\\n286\\t        _namespace: \u0026Namespace,\\n287\\t    ) -\u003e Result\u003cVec\u003cCollectionId\u003e, AxonError\u003e {\\n288\\t        Ok(vec![])\\n289\\t    }\\n290\\t\\n291\\t    /// Resolve a collection identifier to its fully qualified catalog key.\\n292\\t    ///\\n293\\t    /// Concrete adapters should override this when bare collection names need\\n294\\t    /// catalog-aware disambiguation across namespaces or databases.\\n295\\t    fn resolve_collection_key(\\n296\\t        \u0026self,\\n297\\t        collection: \u0026CollectionId,\\n298\\t    ) -\u003e Result\u003cQualifiedCollectionId, AxonError\u003e {\\n299\\t        let (namespace, bare_collection) = Namespace::parse(collection.as_str());\\n300\\t        Ok(QualifiedCollectionId::from_parts(\\n301\\t            \u0026namespace,\\n302\\t            \u0026CollectionId::new(bare_collection),\\n303\\t        ))\\n304\\t    }\\n305\\t\\n306\\t    /// Remove any links whose source or target belongs to the provided\\n307\\t    /// collections.\\n308\\t    ///\\n309\\t    /// The default implementation scans the forward link pseudo-collection and\\n310\\t    /// deletes matching links through [`StorageAdapter::delete_link`], allowing\\n311\\t    /// concrete adapters to clean both pseudo-collection rows and any dedicated\\n312\\t    /// link storage they maintain.\\n313\\t    fn purge_links_for_collections(\\n314\\t        \u0026mut self,\\n315\\t        collections: \u0026[QualifiedCollectionId],\\n316\\t    ) -\u003e Result\u003c(), AxonError\u003e {\\n317\\t        if collections.is_empty() {\\n318\\t            return Ok(());\\n319\\t        }\\n320\\t\\n321\\t        let doomed: BTreeSet\u003c_\u003e = collections.iter().cloned().collect();\\n322\\t        let links = self.range_scan(\u0026Link::links_collection(), None, None, None)?;\\n323\\t        for entity in links {\\n324\\t            let Some(link) = Link::from_entity(\u0026entity) else {\\n325\\t                continue;\\n326\\t            };\\n327\\t\\n328\\t            let source = self.resolve_collection_key(\u0026link.source_collection)?;\\n329\\t            let target = self.resolve_collection_key(\u0026link.target_collection)?;\\n330\\t            if doomed.contains(\u0026source) || doomed.contains(\u0026target) {\\n331\\t                self.delete_link(\\n332\\t                    \u0026link.source_collection,\\n333\\t                    \u0026link.source_id,\\n334\\t                    \u0026link.link_type,\\n335\\t                    \u0026link.target_collection,\\n336\\t                    \u0026link.target_id,\\n337\\t                )?;\\n338\\t            }\\n339\\t        }\\n340\\t\\n341\\t        Ok(())\\n342\\t    }\\n343\\t\\n344\\t    // ── Schema persistence ───────────────────────────────────────────────────\\n345\\t\\n346\\t    /// Persist a [`CollectionSchema`], replacing any previously stored schema for\\n347\\t    /// the same collection.\\n348\\t    ///\\n349\\t    /// The default implementation is a no-op that returns `Ok(())`.\\n350\\t    /// Concrete adapters should override this to provide durable schema storage.\\n351\\t    fn put_schema(\u0026mut self, schema: \u0026CollectionSchema) -\u003e Result\u003c(), AxonError\u003e {\\n352\\t        let _ = schema;\\n353\\t        Ok(())\\n354\\t    }\\n355\\t\\n356\\t    /// Retrieve the [`CollectionSchema`] for a collection, if one exists.\\n357\\t    ///\\n358\\t    /// Returns `Ok(None)` when no schema has been stored for the collection.\\n359\\t    /// The default implementation always returns `Ok(None)`.\\n360\\t    fn get_schema(\u0026self, collection: \u0026CollectionId) -\u003e Result\u003cOption\u003cCollectionSchema\u003e, AxonError\u003e {\\n361\\t        let _ = collection;\\n362\\t        Ok(None)\\n363\\t    }\\n364\\t\\n365\\t    /// Retrieve a specific version of a collection schema.\\n366\\t    ///\\n367\\t    /// Returns `Ok(None)` if the version does not exist.\\n368\\t    /// The default implementation always returns `Ok(None)`.\\n369\\t    fn get_schema_version(\\n370\\t        \u0026self,\\n371\\t        collection: \u0026CollectionId,\\n372\\t        version: u32,\\n373\\t    ) -\u003e Result\u003cOption\u003cCollectionSchema\u003e, AxonError\u003e {\\n374\\t        let _ = (collection, version);\\n375\\t        Ok(None)\\n376\\t    }\\n377\\t\\n378\\t    /// List all schema versions for a collection, returning (version, created_at_ns) pairs\\n379\\t    /// in ascending version order.\\n380\\t    ///\\n381\\t    /// The default implementation returns an empty list.\\n382\\t    fn list_schema_versions(\\n383\\t        \u0026self,\\n384\\t        collection: \u0026CollectionId,\\n385\\t    ) -\u003e Result\u003cVec\u003c(u32, u64)\u003e, AxonError\u003e {\\n386\\t        let _ = collection;\\n387\\t        Ok(vec![])\\n388\\t    }\\n389\\t\\n390\\t    /// Delete the schema for a collection. Returns `Ok(())` whether or not a\\n391\\t    /// schema existed.\\n392\\t    ///\\n393\\t    /// The default implementation is a no-op.\\n394\\t    fn delete_schema(\u0026mut self, collection: \u0026CollectionId) -\u003e Result\u003c(), AxonError\u003e {\\n395\\t        let _ = collection;\\n396\\t        Ok(())\\n397\\t    }\\n398\\t\\n399\\t    // ── Collection presentation persistence ─────────────────────────────────\\n400\\t\\n401\\t    /// Persist a [`CollectionView`], replacing any previously stored view for\\n402\\t    /// the same collection and incrementing its independent version counter.\\n403\\t    ///\\n404\\t    /// Implementations must reject views whose target collection has not been\\n405\\t    /// registered yet.\\n406\\t    ///\\n407\\t    /// Returns the stored view with the adapter-assigned `version` and\\n408\\t    /// `updated_at_ns`.\\n409\\t    fn put_collection_view(\u0026mut self, view: \u0026CollectionView) -\u003e Result\u003cCollectionView, AxonError\u003e {\\n410\\t        Ok(view.clone())\\n411\\t    }\\n412\\t\\n413\\t    /// Retrieve the latest [`CollectionView`] for a collection, if one exists.\\n414\\t    fn get_collection_view(\\n415\\t        \u0026self,\\n416\\t        collection: \u0026CollectionId,\\n417\\t    ) -\u003e Result\u003cOption\u003cCollectionView\u003e, AxonError\u003e {\\n418\\t        let _ = collection;\\n419\\t        Ok(None)\\n420\\t    }\\n421\\t\\n422\\t    /// Delete the collection view for a collection. Returns `Ok(())` whether or\\n423\\t    /// not a view existed.\\n424\\t    fn delete_collection_view(\u0026mut self, collection: \u0026CollectionId) -\u003e Result\u003c(), AxonError\u003e {\\n425\\t        let _ = collection;\\n426\\t        Ok(())\\n427\\t    }\\n428\\t\\n429\\t    // ── Collection registry ──────────────────────────────────────────────────\\n430\\t\\n431\\t    /// Record that a named collection has been explicitly created.\\n432\\t    ///\\n433\\t    /// Implementations must persist this so the collection survives process\\n434\\t    /// restart. The default implementation is a no-op.\\n435\\t    fn register_collection(\u0026mut self, collection: \u0026CollectionId) -\u003e Result\u003c(), AxonError\u003e {\\n436\\t        self.register_collection_in_namespace(collection, \u0026Namespace::default_ns())\\n437\\t    }\\n438\\t\\n439\\t    /// Record that a named collection belongs to a specific namespace.\\n440\\t    ///\\n441\\t    /// Implementations that do not yet distinguish namespaces may ignore the\\n442\\t    /// namespace and treat all collections as belonging to `default.default`.\\n443\\t    fn register_collection_in_namespace(\\n444\\t        \u0026mut self,\\n445\\t        collection: \u0026CollectionId,\\n446\\t        _namespace: \u0026Namespace,\\n447\\t    ) -\u003e Result\u003c(), AxonError\u003e {\\n448\\t        let _ = collection;\\n449\\t        Ok(())\\n450\\t    }\\n451\\t\\n452\\t    /// Return whether a collection is registered within a specific namespace.\\n453\\t    fn collection_registered_in_namespace(\\n454\\t        \u0026self,\\n455\\t        collection: \u0026CollectionId,\\n456\\t        namespace: \u0026Namespace,\\n457\\t    ) -\u003e Result\u003cbool, AxonError\u003e {\\n458\\t        Ok(self\\n459\\t            .list_namespace_collections(namespace)?\\n460\\t            .contains(collection))\\n461\\t    }\\n462\\t\\n463\\t    /// Remove a collection from the registry.\\n464\\t    ///\\n465\\t    /// Returns `Ok(())` whether or not the collection was registered.\\n466\\t    /// The default implementation is a no-op.\\n467\\t    fn unregister_collection(\u0026mut self, collection: \u0026CollectionId) -\u003e Result\u003c(), AxonError\u003e {\\n468\\t        let _ = collection;\\n469\\t        Ok(())\\n470\\t    }\\n471\\t\\n472\\t    /// Return all explicitly-registered collection names, in ascending order.\\n473\\t    ///\\n474\\t    /// The default implementation returns an empty list (suitable for adapters\\n475\\t    /// that do not implement persistent collection registration).\\n476\\t    fn list_collections(\u0026self) -\u003e Result\u003cVec\u003cCollectionId\u003e, AxonError\u003e {\\n477\\t        Ok(vec![])\\n478\\t    }\\n479\\t\\n480\\t    // ── Numeric collection ID mapping (ADR-010) ─────────────────────────\\n481\\t\\n482\\t    /// Resolve a collection's stable numeric ID.\\n483\\t    ///\\n484\\t    /// Returns the auto-assigned numeric ID for a registered collection.\\n485\\t    /// Returns `None` if the collection has not been registered.\\n486\\t    /// The default implementation always returns `None`.\\n487\\t    fn collection_numeric_id(\u0026self, collection: \u0026CollectionId) -\u003e Result\u003cOption\u003cu64\u003e, AxonError\u003e {\\n488\\t        let _ = collection;\\n489\\t        Ok(None)\\n490\\t    }\\n491\\t\\n492\\t    /// Resolve a numeric ID back to a collection name.\\n493\\t    ///\\n494\\t    /// Returns `None` if no collection has the given numeric ID.\\n495\\t    /// The default implementation always returns `None`.\\n496\\t    fn collection_by_numeric_id(\u0026self, numeric_id: u64) -\u003e Result\u003cOption\u003cCollectionId\u003e, AxonError\u003e {\\n497\\t        let _ = numeric_id;\\n498\\t        Ok(None)\\n499\\t    }\\n500\\t\\n501\\t    // ── Secondary index operations (FEAT-013) ───────────────────────────\\n502\\t\\n503\\t    /// Update index entries for an entity.\\n504\\t    ///\\n505\\t    /// Removes any existing index entries for this entity, then inserts new\\n506\\t    /// entries based on the entity's current data and the declared indexes.\\n507\\t    /// Called automatically on every `put` and `compare_and_swap`.\\n508\\t    ///\\n509\\t    /// `old_data` is the previous entity data (for removing stale entries).\\n510\\t    /// `None` if this is a new entity.\\n511\\t    ///\\n512\\t    /// The default implementation is a no-op.\\n513\\t    fn update_indexes(\\n514\\t        \u0026mut self,\\n515\\t        _collection: \u0026CollectionId,\\n516\\t        _entity_id: \u0026EntityId,\\n517\\t        _old_data: Option\u003c\u0026serde_json::Value\u003e,\\n518\\t        _new_data: \u0026serde_json::Value,\\n519\\t        _indexes: \u0026[axon_schema::schema::IndexDef],\\n520\\t    ) -\u003e Result\u003c(), AxonError\u003e {\\n521\\t        Ok(())\\n522\\t    }\\n523\\t\\n524\\t    /// Remove all index entries for a deleted entity.\\n525\\t    ///\\n526\\t    /// The default implementation is a no-op.\\n527\\t    fn remove_index_entries(\\n528\\t        \u0026mut self,\\n529\\t        _collection: \u0026CollectionId,\\n530\\t        _entity_id: \u0026EntityId,\\n531\\t        _data: \u0026serde_json::Value,\\n532\\t        _indexes: \u0026[axon_schema::schema::IndexDef],\\n533\\t    ) -\u003e Result\u003c(), AxonError\u003e {\\n534\\t        Ok(())\\n535\\t    }\\n536\\t\\n537\\t    /// Look up entity IDs by exact index value (equality query).\\n538\\t    ///\\n539\\t    /// Returns entity IDs in ascending order. Returns an empty vec if no\\n540\\t    /// entities match. Implementations that do not maintain in-memory indexes\\n541\\t    /// should return `Err` so the caller falls through to a full scan.\\n542\\t    fn index_lookup(\\n543\\t        \u0026self,\\n544\\t        _collection: \u0026CollectionId,\\n545\\t        _field: \u0026str,\\n546\\t        _value: \u0026IndexValue,\\n547\\t    ) -\u003e Result\u003cVec\u003cEntityId\u003e, AxonError\u003e {\\n548\\t        Err(AxonError::Storage(\\n549\\t            \\\"index_lookup not supported by this adapter\\\".into(),\\n550\\t        ))\\n551\\t    }\\n552\\t\\n553\\t    /// Range scan on an index, returning entity IDs whose indexed value\\n554\\t    /// falls within the given bounds.\\n555\\t    ///\\n556\\t    /// Returns entity IDs sorted by indexed value, then by entity ID.\\n557\\t    /// Implementations that